24	// SetServiceRunFactory installs a service factory for RunWithConfigViaService.
25	// Pass nil to restore production behavior. Exported for cmd/ integration tests.
26	//
27	// Production reachability: invoked from init() with nil so the symbol is
28	// reachable from main() under deadcode RTA. Real overrides come from cmd/
29	// integration tests at test-setup time.
30	func SetServiceRunFactory(f func(workDir string) (agentlib.FizeauService, error)) {
31		serviceRunFactory = f
