415	// TestProviderConnectivityViaService runs a HealthCheck against the named
416	// harness and translates the result into a ProviderStatus. It is the
417	// production replacement for Runner.TestProviderConnectivity.
418	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
419		status := ProviderStatus{Reachable: false}
420		if ctx == nil {
421			ctx = context.Background()
422		}
423		if harnessName == "virtual" || harnessName == "agent" {
424			status.Reachable = true
425			status.CreditsOK = true
426			return status
427		}
428		svc, err := NewServiceFromWorkDir(workDir)
429		if err != nil {
430			status.Error = err.Error()
431			return status
432		}
433		if timeout > 0 {
434			var cancel context.CancelFunc
435			ctx, cancel = context.WithTimeout(ctx, timeout)
436			defer cancel()
437		}
438		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
439			errStr := strings.ToLower(err.Error())
440			status.Error = err.Error()
441			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
442				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
443				status.CreditsOK = false
444			}
445			return status
446		}
447		status.Reachable = true
448		status.CreditsOK = true
449		return status
450	}
