452	// ValidateForExecuteLoopViaService is the production replacement for
453	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
454	// will pick at claim time). When harness is specified it confirms the harness
455	// exists in the service registry and (when model is set) attempts a
456	// ResolveRoute pre-flight.
457	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
458		if harnessName == "" {
459			return nil
460		}
461		if ctx == nil {
462			ctx = context.Background()
463		}
464		svc, err := NewServiceFromWorkDir(workDir)
465		if err != nil {
466			return fmt.Errorf("agent: build service: %w", err)
467		}
468		infos, err := svc.ListHarnesses(ctx)
469		if err != nil {
470			return fmt.Errorf("agent: list harnesses: %w", err)
471		}
472		found := false
473		for _, info := range infos {
474			if info.Name == harnessName {
475				found = true
476				if !info.Available {
477					return fmt.Errorf("agent: harness %s not available", harnessName)
478				}
479				break
480			}
481		}
482		if !found {
483			return fmt.Errorf("agent: unknown harness: %s", harnessName)
484		}
485	
486		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
487		// model is provided and provider/model-ref are not set.
488		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
489			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
490				Model:    model,
491				Harness:  harnessName,
492				ModelRef: modelRef,
493				Provider: provider,
494			}); err != nil {
495				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
496			}
497		}
498		return nil
499	}
