501	// ValidateEffortForRunViaService rejects effort requests that no currently
502	// available harness can satisfy. `ddx agent run` passes effort through to the
503	// service rather than resolving a route locally, but the command still needs a
504	// fast failure for obviously impossible combinations so operators get a useful
505	// error instead of a silent success path.
506	func ValidateEffortForRunViaService(ctx context.Context, workDir, profile, effort string) error {
507		if effort == "" {
508			return nil
509		}
510		if ctx == nil {
511			ctx = context.Background()
512		}
513		svc, err := NewServiceFromWorkDir(workDir)
514		if err != nil {
515			return fmt.Errorf("agent: build service: %w", err)
516		}
517		infos, err := svc.ListHarnesses(ctx)
518		if err != nil {
519			return fmt.Errorf("agent: list harnesses: %w", err)
520		}
521		registry := newHarnessRegistry()
522		for _, info := range infos {
523			if !info.Available {
524				continue
525			}
526			if harness, ok := registry.Get(info.Name); ok && harness.EffortFlag != "" {
527				return nil
528			}
529		}
530		if profile == "" {
531			return fmt.Errorf("agent: no selected provider candidate satisfies effort %q", effort)
532		}
533		return fmt.Errorf("agent: no selected provider candidate satisfies profile %q and effort %q", profile, effort)
534	}
