// Build the executor: either the test override or the real single-tier executor.
var executor agent.ExecuteBeadExecutor
if f.tryExecutorOverride != nil {
	executor = f.tryExecutorOverride
} else {
	executor = agent.ExecuteBeadExecutorFunc(func(ctx context.Context, execBeadID string) (agent.ExecuteBeadReport, error) {
		var inferredTier escalation.ModelTier
		if autoInferTier {
			if b, getErr := store.Get(execBeadID); getErr == nil {
				inferredTier = escalation.InferTier(b)
			} else {
				inferredTier = escalation.TierCheap
			}
		}

		loopOverrides := config.CLIOverrides{
			Harness:           harness,
			Model:             model,
			Provider:          provider,
			ModelRef:          modelRef,
			Profile:           profile,
			Effort:            effort,
			MinPower:          minPower,
			MaxPower:          maxPower,
			OpaquePassthrough: true, // ddx try treats flags as opaque passthrough
		}
		if requestTimeout > 0 {
			loopOverrides.ProviderRequestTimeout = &requestTimeout
		}
		attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
		// Use the git override when present — allows test injection for
		// RecoverOrphans and gate-context evaluation without a real repo.
		var gitOps agent.GitOps = &agent.RealGitOps{}
		if f.executeBeadGitOverride != nil {
			gitOps = f.executeBeadGitOverride
		}
		// Recover orphaned worktrees from previous crashed runs before
		// spawning a new worker.
		agent.RecoverOrphans(gitOps, projectRoot, execBeadID)
		runtime := agent.ExecuteBeadRuntime{
			FromRev:         fromRev,
			Output:          cmd.OutOrStdout(),
			BeadEvents:      bead.NewStore(filepath.Join(projectRoot, ".ddx")),
			ResourceChecker: resourceChecker,
		}
		if f.AgentRunnerOverride != nil {
			runtime.AgentRunner = f.AgentRunnerOverride
		}
		res, execErr := agent.ExecuteBeadWithConfig(ctx, projectRoot, execBeadID, attemptRcfg, runtime, gitOps)
		if execErr != nil && res == nil {
			return agent.ExecuteBeadReport{}, execErr
		}
		if res != nil && agent.IsResourceExhaustedStatus(res.Status) {
			return agent.ReportFromExecuteBeadResult(res, string(inferredTier)), nil
		}
		if execErr != nil {
			agent.MarkResultExecutionError(res, execErr)
			return agent.ReportFromExecuteBeadResult(res, string(inferredTier)), nil
		}
		if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
			// Evaluate required execution gates before landing, mirroring
			// the server-side evaluateGatesAndSubmit pattern. BuildLandingGateContext
			// pins ResultRev to a transient ref and checks out an ephemeral
			// worktree; failures are soft-logged and gate eval is skipped.
			buildGateCtx := agent.BuildLandingGateContext
			if f.tryBuildGateContextOverride != nil {
				buildGateCtx = f.tryBuildGateContextOverride
			}
			wt, ids, gateCleanup, ctxErr := buildGateCtx(projectRoot, res, gitOps)
			if ctxErr != nil {
				fmt.Fprintf(os.Stderr, "ddx: warning: gate-context setup failed: %v (skipping required-gate eval)\n", ctxErr)
			}
			if gateCleanup != nil {
				defer gateCleanup()
			}
			if wt != "" {
				checksAbs := filepath.Join(projectRoot, res.ExecutionDir, "checks.json")
				checksRel := filepath.Join(res.ExecutionDir, "checks.json")
				anyFailed, ratchetFailed, evalErr := agent.EvaluateRequiredGatesForResult(wt, ids, res, projectRoot, checksAbs, checksRel)
				if evalErr != nil {
					fmt.Fprintf(os.Stderr, "ddx: warning: gate evaluation failed: %v (skipping)\n", evalErr)
				} else if anyFailed || ratchetFailed {
					preserveRef := agent.PreserveRef(res.BeadID, res.BaseRev)
					if upErr := gitOps.UpdateRef(projectRoot, preserveRef, res.ResultRev); upErr != nil {
						fmt.Fprintf(os.Stderr, "ddx: warning: preserving result ref %s failed: %v\n", preserveRef, upErr)
					} else {
						res.PreserveRef = preserveRef
					}
					res.Outcome = "preserved"
					if ratchetFailed {
						res.Reason = agent.RatchetPreserveReason
					} else {
						res.Reason = "post-run checks failed"
					}
					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
					res.Detail = agent.ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
					_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
					return agent.ReportFromExecuteBeadResult(res, string(inferredTier)), nil
				}
			}

			targetBead, _ := store.Get(execBeadID)
			landRes, _, landErr := agent.SubmitWithPreMergeChecks(
				ctx, projectRoot, targetBead, res,
				func(req agent.LandRequest) (*agent.LandResult, error) { return localCoord.Submit(req) },
				bead.NewStore(filepath.Join(projectRoot, ".ddx")),
				resolveClaimAssignee(), "ddx try",
				nil,
			)
			if landErr == nil {
				agent.ApplyLandResultToExecuteBeadResult(res, landRes)
				_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
			} else {
				agent.MarkResultLandError(projectRoot, res, landErr)
				_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
				return agent.ReportFromExecuteBeadResult(res, string(inferredTier)), nil
			}
		} else if res != nil && (res.Outcome == agent.ExecuteBeadOutcomeTaskFailed || res.ExitCode != 0) {
			if res.ResultRev != "" && res.ResultRev != res.BaseRev {
				res.Outcome = "preserved"
			} else {
				res.Outcome = "error"
			}
			res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
		} else if res != nil && res.ResultRev == res.BaseRev {
			res.Outcome = "no-changes"
			res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
		}
		tierStr := ""
		if inferredTier != "" {
			tierStr = string(inferredTier)
		}
		return agent.ReportFromExecuteBeadResult(res, tierStr), nil
	})
}

