60	// ReportFromExecuteBeadResult maps the detailed worker/orchestrator result
61	// into the loop-facing report shape used by ddx work and ddx try.
62	func ReportFromExecuteBeadResult(res *ExecuteBeadResult, tier string) ExecuteBeadReport {
63		if res == nil {
64			return ExecuteBeadReport{}
65		}
66		return ExecuteBeadReport{
67			BeadID:                      res.BeadID,
68			AttemptID:                   res.AttemptID,
69			WorkerID:                    res.WorkerID,
70			Harness:                     res.Harness,
71			Provider:                    res.Provider,
72			Model:                       res.Model,
