76			PredictedCostUSDPer1kTokens: res.PredictedCostUSDPer1kTokens,
77			PredictedCostSource:         res.PredictedCostSource,
78			Status:                      res.Status,
79			Detail:                      res.Detail,
80			Error:                       res.Error,
81			Stderr:                      res.Stderr,
82			RateLimitBudget:             res.RateLimitBudget,
83			SessionID:                   res.SessionID,
84			BaseRev:                     res.BaseRev,
85			ResultRev:                   res.ResultRev,
86			PreserveRef:                 res.PreserveRef,
87			NoChangesRationale:          res.NoChangesRationale,
