1	package agent
2	
3	import (
4		"encoding/json"
5		"errors"
6		"fmt"
7		"os"
8		"path/filepath"
9		"sort"
10		"strings"
11		"time"
12	)
13	
14	// RunStateFileName is the basename of the live run-state file, relative to
15	// the project's .ddx directory.
16	const RunStateFileName = "run-state.json"
17	
18	// RunStateDirName is the .ddx subdirectory containing per-attempt live-state
19	// records. The legacy .ddx/run-state.json file remains as a compatibility
20	// summary view for older operators.
21	const RunStateDirName = "run-state"
22	
23	// RunStateLivenessTTL is the default expiry window written to refreshed
24	// attempt liveness records.
25	const RunStateLivenessTTL = 2 * time.Minute
26	
27	// RunState is the on-disk record of an executing bead attempt. It is written at
28	// execute-bead start, refreshed while the agent runs, and removed on completion
29	// (or on orphan recovery of a crashed worker). Operators and HELIX consume this
30	// state to observe what is running without polling the bead tracker.
31	//
32	// See CONTRACT-001 §5 (Always-on runtime metrics and provenance).
33	type RunState struct {
34		BeadID       string    `json:"bead_id"`
35		AttemptID    string    `json:"attempt_id"`
36		Harness      string    `json:"harness,omitempty"`
37		Model        string    `json:"model,omitempty"`
38		StartedAt    time.Time `json:"started_at"`
39		WorktreePath string    `json:"worktree_path"`
40		PID          int       `json:"pid,omitempty"`
41		SessionID    string    `json:"session_id,omitempty"`
42		RefreshedAt  time.Time `json:"refreshed_at,omitempty"`
43		ExpiresAt    time.Time `json:"expires_at,omitempty"`
44		// Candidate-cycle fields mirror cleanup metadata so operators can see
45		// which candidate phase owns a long-lived attempt worktree.
46		CandidateCyclePhase string `json:"candidate_cycle_phase,omitempty"`
47		CandidateRef        string `json:"candidate_ref,omitempty"`
48		CandidateRev        string `json:"candidate_rev,omitempty"`
49		CycleIndex          int    `json:"cycle_index,omitempty"`
50		ReviewActive        bool   `json:"review_active,omitempty"`
51		RepairActive        bool   `json:"repair_active,omitempty"`
52	}
53	
54	// runStatePath returns the absolute path of the run-state file for the
55	// project rooted at projectRoot.
56	func runStatePath(projectRoot string) string {
57		return filepath.Join(projectRoot, ".ddx", RunStateFileName)
58	}
59	
60	func runStateDirPath(projectRoot string) string {
61		return filepath.Join(projectRoot, ".ddx", RunStateDirName)
62	}
63	
64	func runStateAttemptPath(projectRoot, attemptID string) (string, error) {
65		name, err := runStateAttemptFileName(attemptID)
66		if err != nil {
67			return "", err
68		}
69		return filepath.Join(runStateDirPath(projectRoot), name), nil
70	}
71	
72	func runStateAttemptFileName(attemptID string) (string, error) {
73		attemptID = strings.TrimSpace(attemptID)
74		if attemptID == "" {
75			return "", errors.New("run-state: attempt_id is empty")
76		}
77		if filepath.Base(attemptID) != attemptID || strings.ContainsAny(attemptID, `/\`) {
78			return "", fmt.Errorf("run-state: invalid attempt_id %q", attemptID)
79		}
80		return attemptID + ".json", nil
81	}
82	
83	func normalizeRunState(state RunState) RunState {
84		now := time.Now().UTC()
85		if state.StartedAt.IsZero() {
86			state.StartedAt = now
87		}
88		if state.RefreshedAt.IsZero() {
89			state.RefreshedAt = now
90		}
91		if state.ExpiresAt.IsZero() {
92			state.ExpiresAt = state.RefreshedAt.Add(RunStateLivenessTTL)
93		}
94		if state.PID == 0 {
95			state.PID = os.Getpid()
96		}
97		return state
98	}
99	
100	// WriteRunState atomically writes state to a per-attempt file under
101	// .ddx/run-state/ and refreshes .ddx/run-state.json as a legacy compatibility
102	// summary. Writes go to sibling tmp files and are then renamed into place so
103	// readers never observe a partial record.
104	func WriteRunState(projectRoot string, state RunState) error {
105		if projectRoot == "" {
106			return errors.New("WriteRunState: projectRoot is empty")
107		}
108		state = normalizeRunState(state)
109		attemptPath, err := runStateAttemptPath(projectRoot, state.AttemptID)
110		if err != nil {
111			return err
112		}
113		ddxDir := filepath.Join(projectRoot, ".ddx")
114		attemptDir := filepath.Dir(attemptPath)
115		if err := os.MkdirAll(ddxDir, 0o755); err != nil {
116			return fmt.Errorf("run-state: mkdir .ddx: %w", err)
117		}
118		if err := os.MkdirAll(attemptDir, 0o755); err != nil {
119			return fmt.Errorf("run-state: mkdir attempts: %w", err)
120		}
121		if err := writeRunStateJSON(attemptPath, state); err != nil {
122			return err
123		}
124		return writeRunStateJSON(runStatePath(projectRoot), state)
125	}
126	
127	func writeRunStateJSON(final string, state RunState) error {
128		dir := filepath.Dir(final)
129		if err := os.MkdirAll(dir, 0o755); err != nil {
130			return fmt.Errorf("run-state: mkdir: %w", err)
131		}
132		data, err := json.MarshalIndent(state, "", "  ")
133		if err != nil {
134			return fmt.Errorf("run-state: marshal: %w", err)
135		}
136		data = append(data, '\n')
137	
138		tmp, err := os.CreateTemp(dir, "run-state-*.json.tmp")
139		if err != nil {
140			return fmt.Errorf("run-state: create tmp: %w", err)
141		}
142		tmpName := tmp.Name()
143		if _, err := tmp.Write(data); err != nil {
144			_ = tmp.Close()
145			_ = os.Remove(tmpName)
146			return fmt.Errorf("run-state: write tmp: %w", err)
147		}
