27	// RunState is the on-disk record of an executing bead attempt. It is written at
28	// execute-bead start, refreshed while the agent runs, and removed on completion
29	// (or on orphan recovery of a crashed worker). Operators and HELIX consume this
30	// state to observe what is running without polling the bead tracker.
31	//
32	// See CONTRACT-001 §5 (Always-on runtime metrics and provenance).
33	type RunState struct {
34		BeadID       string    `json:"bead_id"`
35		AttemptID    string    `json:"attempt_id"`
36		Harness      string    `json:"harness,omitempty"`
37		Model        string    `json:"model,omitempty"`
38		StartedAt    time.Time `json:"started_at"`
39		WorktreePath string    `json:"worktree_path"`
40		PID          int       `json:"pid,omitempty"`
41		SessionID    string    `json:"session_id,omitempty"`
42		RefreshedAt  time.Time `json:"refreshed_at,omitempty"`
43		ExpiresAt    time.Time `json:"expires_at,omitempty"`
44		// Candidate-cycle fields mirror cleanup metadata so operators can see
45		// which candidate phase owns a long-lived attempt worktree.
46		CandidateCyclePhase string `json:"candidate_cycle_phase,omitempty"`
47		CandidateRef        string `json:"candidate_ref,omitempty"`
48		CandidateRev        string `json:"candidate_rev,omitempty"`
49		CycleIndex          int    `json:"cycle_index,omitempty"`
50		ReviewActive        bool   `json:"review_active,omitempty"`
51		RepairActive        bool   `json:"repair_active,omitempty"`
52	}
