100	// WriteRunState atomically writes state to a per-attempt file under
101	// .ddx/run-state/ and refreshes .ddx/run-state.json as a legacy compatibility
102	// summary. Writes go to sibling tmp files and are then renamed into place so
103	// readers never observe a partial record.
104	func WriteRunState(projectRoot string, state RunState) error {
105		if projectRoot == "" {
106			return errors.New("WriteRunState: projectRoot is empty")
107		}
108		state = normalizeRunState(state)
109		attemptPath, err := runStateAttemptPath(projectRoot, state.AttemptID)
110		if err != nil {
111			return err
112		}
113		ddxDir := filepath.Join(projectRoot, ".ddx")
114		attemptDir := filepath.Dir(attemptPath)
115		if err := os.MkdirAll(ddxDir, 0o755); err != nil {
116			return fmt.Errorf("run-state: mkdir .ddx: %w", err)
117		}
118		if err := os.MkdirAll(attemptDir, 0o755); err != nil {
119			return fmt.Errorf("run-state: mkdir attempts: %w", err)
120		}
121		if err := writeRunStateJSON(attemptPath, state); err != nil {
122			return err
123		}
124		return writeRunStateJSON(runStatePath(projectRoot), state)
125	}
