// TestTry_RecoversOrphanedWorktreesBeforeSpawn verifies that RecoverOrphans
// runs before the executor is built, so stale run-state from crashed workers
// is swept even when tryExecutorOverride is set.
func TestTry_RecoversOrphanedWorktreesBeforeSpawn(t *testing.T) {
	env := NewTestEnvironment(t)
	store := bead.NewStore(env.Dir + "/.ddx")
	require.NoError(t, store.Init())
	require.NoError(t, store.Create(&bead.Bead{
		ID:    "orphan-bead-001",
		Title: "Orphan recovery bead",
	}))

	// Write a stale run-state simulating a crashed previous worker.
	staleState := agent.RunState{
		BeadID:    "orphan-bead-001",
		AttemptID: "stale-attempt-001",
	}
	require.NoError(t, agent.WriteRunState(env.Dir, staleState))

	states, err := agent.ReadRunStates(env.Dir)
	require.NoError(t, err)
	require.Len(t, states, 1, "stale run-state must exist before ddx try")

	// Fake git ops: return empty worktrees so RecoverOrphans has no orphaned
	// worktrees to remove via git, but will still sweep the stale run-state.
	git := &fakeExecuteBeadGit{mainHeadRev: "aaaa1111"}

	factory := NewCommandFactory(env.Dir)
	factory.executeBeadGitOverride = git
	factory.AgentRunnerOverride = &tryHookRunnerStub{t: t}
	factory.tryExecutorOverride = agent.ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		return agent.ExecuteBeadReport{
			BeadID: beadID,
			Status: agent.ExecuteBeadStatusSuccess,
		}, nil
	})

	_, _ = executeCommand(factory.NewRootCommand(), "try", "orphan-bead-001",
		"--no-review", "--no-review-i-know-what-im-doing")

	states, err = agent.ReadRunStates(env.Dir)
	require.NoError(t, err)
	var found bool
	for _, s := range states {
		if s.BeadID == "orphan-bead-001" {
			found = true
		}
	}
	assert.False(t, found, "RecoverOrphans must clear stale run-state for the target bead before the executor is built")
}

// TestTry_AppliesGateContextToLanding verifies that ddx try invokes
// BuildLandingGateContext when the real executor produces commits. The
// tryBuildGateContextOverride seam captures the call without requiring a
// functioning git server for the subsequent land step.
func TestTry_AppliesGateContextToLanding(t *testing.T) {
	git := &fakeExecuteBeadGit{
		mainHeadRev: "aaaa1111",
		wtHeadRev:   "bbbb2222", // agent produced a commit
	}
	runner := &fakeAgentRunner{result: &agent.Result{ExitCode: 0}}
	factory := newExecuteBeadFactory(t, git, runner)

	var gateCtxCalled bool
	var capturedBeadID string
	factory.tryBuildGateContextOverride = func(_ string, res *agent.ExecuteBeadResult, _ agent.GitOps) (string, []string, func(), error) {
		gateCtxCalled = true
		capturedBeadID = res.BeadID
		// Return empty worktree so gate eval is skipped; we only verify the call.
		return "", nil, nil, nil
	}

	// No tryExecutorOverride — runs the real executor closure that calls buildGateCtx.
	// The command may exit non-zero (land error with fake revs) — that is acceptable.
	_, _ = executeCommand(factory.NewRootCommand(), "try", "my-bead",
		"--no-review", "--no-review-i-know-what-im-doing")

	assert.True(t, gateCtxCalled,
		"ddx try must call BuildLandingGateContext when the executor produces commits")
	assert.Equal(t, "my-bead", capturedBeadID,
		"gate context must receive the result for the targeted bead")
}

// TestTry_PreservesJSONResultSchema_SameAsExecuteBead verifies that the
// ExecuteBeadReport emitted by ddx try carries the schema fields operators
// depend on: bead_id, status, result_rev, and preserve_ref.
func TestTry_PreservesJSONResultSchema_SameAsExecuteBead(t *testing.T) {
	cases := []struct {
		name     string
		report   agent.ExecuteBeadReport
		wantKeys []string
	}{
		{
			name: "success_with_rev",
			report: agent.ExecuteBeadReport{
				BeadID:    "schema-bead-001",
				Status:    agent.ExecuteBeadStatusSuccess,
				ResultRev: "deadbeef01234567",
			},
			wantKeys: []string{"bead:", "status:", "result_rev:"},
		},
		{
			name: "preserved_with_ref",
			report: agent.ExecuteBeadReport{
				BeadID:      "schema-bead-002",
				Status:      agent.ExecuteBeadStatusPreservedNeedsReview,
				ResultRev:   "deadbeef01234567",
				PreserveRef: "refs/ddx/iterations/schema-bead-002/20260101T000000Z-deadbeef0123",
			},
			wantKeys: []string{"bead:", "status:", "result_rev:", "preserve_ref:"},
		},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			env := NewTestEnvironment(t)
			store := bead.NewStore(env.Dir + "/.ddx")
			require.NoError(t, store.Init())
			require.NoError(t, store.Create(&bead.Bead{
				ID:    tc.report.BeadID,
				Title: "Schema test bead",
			}))

			want := tc.report
			factory := NewCommandFactory(env.Dir)
			factory.AgentRunnerOverride = &tryHookRunnerStub{t: t}
			factory.tryExecutorOverride = agent.ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (agent.ExecuteBeadReport, error) {
				want.BeadID = beadID
				return want, nil
			})
			out, _ := executeCommand(factory.NewRootCommand(), "try", tc.report.BeadID,
				"--no-review", "--no-review-i-know-what-im-doing")

			for _, key := range tc.wantKeys {
				assert.Contains(t, out, key,
					"ddx try output must contain field %q (ExecuteBeadReport schema contract)", key)
			}
		})
	}
}

// TestTry_ExitCodeContract_0_1_2 verifies that ddx try maps execution statuses
// to the documented exit codes: 0 for success/already_satisfied, 1 for
// preserved/no_changes, 2 for failures.
func TestTry_ExitCodeContract_0_1_2(t *testing.T) {
	cases := []struct {
		name     string
		status   string
		wantCode int
	}{
		{name: "success", status: agent.ExecuteBeadStatusSuccess, wantCode: 0},
		{name: "already_satisfied", status: agent.ExecuteBeadStatusAlreadySatisfied, wantCode: 0},
		{name: "preserved_needs_review", status: agent.ExecuteBeadStatusPreservedNeedsReview, wantCode: 1},
		{name: "no_changes", status: agent.ExecuteBeadStatusNoChanges, wantCode: 1},
		{name: "execution_failed", status: agent.ExecuteBeadStatusExecutionFailed, wantCode: 2},
		{name: "other_terminal", status: "other_terminal_status", wantCode: 2},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			env := NewTestEnvironment(t)
			store := bead.NewStore(env.Dir + "/.ddx")
			require.NoError(t, store.Init())
			beadID := "exit-code-bead-" + strings.ReplaceAll(tc.name, "_", "-")
			require.NoError(t, store.Create(&bead.Bead{
				ID:    beadID,
				Title: "Exit code test bead",
			}))

			factory := NewCommandFactory(env.Dir)
			factory.AgentRunnerOverride = &tryHookRunnerStub{t: t}
			factory.tryExecutorOverride = agent.ExecuteBeadExecutorFunc(func(_ context.Context, id string) (agent.ExecuteBeadReport, error) {
				return agent.ExecuteBeadReport{BeadID: id, Status: tc.status}, nil
			})

			_, err := executeCommand(factory.NewRootCommand(), "try", beadID,
				"--no-review", "--no-review-i-know-what-im-doing")

			if tc.wantCode == 0 {
				assert.NoError(t, err, "status %s must exit 0", tc.status)
			} else {
				require.Error(t, err, "status %s must exit non-zero", tc.status)
				var exitErr *ExitError
				require.ErrorAs(t, err, &exitErr, "error must be *ExitError for status %s", tc.status)
				assert.Equal(t, tc.wantCode, exitErr.Code,
					"status %s must exit %d", tc.status, tc.wantCode)
			}
		})
	}
}

